public static class BaseUpgradeLogic { public static bool CanUpgrade(StorageState storage,BaseUpgradeDefinition upgrade){ if(storage==null||upgrade==null)return false; foreach(CraftIngredient i in upgrade.Cost) if(storage.GetTotalAmount(i.ItemId)<i.Amount)return false; return true;} public static bool TryApplyUpgrade(StorageState storage,BaseProgressState progress,BaseUpgradeDefinition upgrade){ if(storage==null||progress==null||upgrade==null||!CanUpgrade(storage,upgrade))return false; foreach(CraftIngredient i in upgrade.Cost) storage.RemoveItem(i.ItemId,i.Amount); progress.IncreaseUpgradeLevel(upgrade.Id); return true;} }